import numpy as np

class QSVM:
    def __init__(self, n_qubits=2, C=1.0):
        self.n_qubits = n_qubits
        self.dim = 2 ** n_qubits
        self.C = C
        self.X_train = None
        self.y_train = None
        self.alpha = None
        self.b = 0

    def _feature_map(self, x):
        state = np.ones(self.dim, dtype=complex) / np.sqrt(self.dim)
        for i in range(self.dim):
            bits = format(i, f'0{self.n_qubits}b')
            phase = sum(x[q] for q in range(self.n_qubits) if bits[q] == '1' and q < len(x))
            for q1 in range(self.n_qubits):
                for q2 in range(q1+1, self.n_qubits):
                    if bits[q1] == '1' and bits[q2] == '1':
                        if q1 < len(x) and q2 < len(x):
                            phase += x[q1] * x[q2]
            state[i] *= np.exp(1j * phase)
        return state

    def quantum_kernel(self, x1, x2):
        s1, s2 = self._feature_map(x1), self._feature_map(x2)
        return np.abs(np.vdot(s1, s2)) ** 2

    def fit(self, X, y):
        self.X_train = X
        self.y_train = np.array(y)
        n = len(X)

        K = np.array([[self.quantum_kernel(X[i], X[j]) for j in range(n)] for i in range(n)])

        # Simplified coordinate ascent
        self.alpha = np.zeros(n)
        for _ in range(100):
            for i in range(n):
                grad = 1 - y[i] * np.sum(self.alpha * y * K[i, :])
                self.alpha[i] = max(0, min(self.C, self.alpha[i] + grad / (K[i,i] + 1e-8)))

        # Bias
        sv_mask = self.alpha > 1e-7
        if np.any(sv_mask):
            self.b = np.mean(y[sv_mask] - np.sum(self.alpha * y * K[:, sv_mask], axis=0))
        return self

    def predict(self, X):
        preds = []
        for x in X:
            k_vals = np.array([self.quantum_kernel(x, x_t) for x_t in self.X_train])
            decision = np.sum(self.alpha * self.y_train * k_vals) + self.b
            preds.append(np.sign(decision))
        return np.array(preds)

    def score(self, X, y):
        return np.mean(self.predict(X) == y)

np.random.seed(42)
n = 30
X = np.vstack([np.random.randn(n//2, 2) + [2, 2], np.random.randn(n//2, 2) - [2, 2]])
y = np.array([1]*(n//2) + [-1]*(n//2))

qsvm = QSVM(n_qubits=2, C=1.0)
qsvm.fit(X[:24], y[:24])

print(f'Train accuracy: {qsvm.score(X[:24], y[:24]):.2%}')
print(f'Test accuracy: {qsvm.score(X[24:], y[24:]):.2%}')

import numpy as np

def kernel_comparison(X, y, n_splits=5):
    n = len(X)
    n_qubits = min(X.shape[1], 2)
    dim = 2 ** n_qubits

    # Quantum kernel
    def qfm(x):
        state = np.ones(dim, dtype=complex) / np.sqrt(dim)
        for i in range(dim):
            bits = format(i, f'0{n_qubits}b')
            phase = sum(x[q] for q in range(n_qubits) if bits[q] == '1' and q < len(x))
            for q1 in range(n_qubits):
                for q2 in range(q1+1, n_qubits):
                    if bits[q1] == '1' and bits[q2] == '1' and q1 < len(x) and q2 < len(x):
                        phase += x[q1] * x[q2]
            state[i] *= np.exp(1j * phase)
        return state

    def quantum_k(x1, x2):
        return np.abs(np.vdot(qfm(x1), qfm(x2))) ** 2

    def rbf_k(x1, x2, gamma=1.0):
        return np.exp(-gamma * np.sum((x1 - x2) ** 2))

    def poly_k(x1, x2, degree=2):
        return (np.dot(x1, x2) + 1) ** degree

    def train_and_eval(K_train, y_train, K_test, y_test, alpha=0.1):
        w = np.linalg.solve(K_train + alpha * np.eye(len(K_train)), y_train)
        preds = np.sign(K_test @ w)
        return np.mean(preds == y_test)

    results = {'Quantum': [], 'RBF': [], 'Polynomial': []}

    # Cross-validation
    fold_size = n // n_splits
    for fold in range(n_splits):
        test_idx = np.arange(fold * fold_size, (fold + 1) * fold_size)
        train_idx = np.array([i for i in range(n) if i not in test_idx])

        X_train, X_test = X[train_idx], X[test_idx]
        y_train, y_test = y[train_idx], y[test_idx]

        for name, kfunc in [('Quantum', quantum_k), ('RBF', rbf_k), ('Polynomial', poly_k)]:
            K_train = np.array([[kfunc(X_train[i], X_train[j]) 
                               for j in range(len(X_train))] 
                              for i in range(len(X_train))])
            K_test = np.array([[kfunc(X_test[i], X_train[j]) 
                              for j in range(len(X_train))] 
                             for i in range(len(X_test))])

            acc = train_and_eval(K_train, y_train, K_test, y_test)
            results[name].append(acc)

    return {k: np.mean(v) for k, v in results.items()}

np.random.seed(42)
n = 50
X = np.random.randn(n, 2)
y = np.sign(X[:, 0] * X[:, 1])

results = kernel_comparison(X, y)
print('Cross-Validation Accuracy:')
for kernel, acc in results.items():
    print(f'  {kernel}: {acc:.2%}')
